type StatusLineInput struct {
	TaskID      string
	TurnIndex   int
	Message     string
	SinceLastMS int64
	Limit       int
}

func StatusLine(in StatusLineInput) string {
	limit := in.Limit
	if limit <= 0 {
		limit = DefaultLineLimit
	}
	msg := strings.TrimSpace(in.Message)
	prefix := CompactIdentity(in.TaskID, in.TurnIndex)
	age := CompactElapsed(in.SinceLastMS)
	switch {
	case prefix == "" && age == "":
		return BoundedText(msg, limit)
	case prefix == "":
		return BoundedText(strings.TrimSpace(age+" "+msg), limit)
	case msg == "" && age == "":
		return BoundedText(prefix, limit)
	case msg == "":
		return BoundedText(prefix+" "+age, limit)
	case age == "":
		return BoundedText(prefix+" "+msg, limit)
	default:
		return BoundedText(prefix+" "+age+" "+msg, limit)
	}
}

func CompactElapsed(ms int64) string {
	if ms <= 0 {
		return ""
	}
	seconds := int64((time.Duration(ms)*time.Millisecond + 500*time.Millisecond) / time.Second)
	if seconds <= 0 {
		seconds = 1
	}
	var raw string
	switch {
	case seconds < 60:
		raw = fmt.Sprintf("+%ds", seconds)
	case seconds < 3600:
		raw = fmt.Sprintf("+%dm%02ds", seconds/60, seconds%60)
	default:
		hours := seconds / 3600
		minutes := (seconds % 3600) / 60
		if hours < 10 {
			raw = fmt.Sprintf("+%dh%02dm", hours, minutes)
		} else {
			raw = fmt.Sprintf("+%dh", hours)
		}
	}
	return fmt.Sprintf("%*s", compactElapsedWidth, raw)
}

func CompactIdentity(taskID string, turnIndex int) string {
	taskID = CompactTaskID(taskID)
	switch {
	case taskID != "" && turnIndex > 0:
		return fmt.Sprintf("%s #%*d", taskID, compactTurnWidth, turnIndex)
	case taskID != "":
		return taskID
	case turnIndex > 0:
		return fmt.Sprintf("#%*d", compactTurnWidth, turnIndex)
	default:
		return ""
	}
}

func CompactTaskID(taskID string) string {
	taskID = strings.TrimSpace(taskID)
	if taskID == "" {
		return ""
	}
	return BoundedText(taskID, 24)
}

func TaskID(sessionID string, meta map[string]string) string {
	for _, key := range []string{"task_id", "bead_id", "correlation_id"} {
		if meta != nil && strings.TrimSpace(meta[key]) != "" {
			return strings.TrimSpace(meta[key])
		}
	}
	return sessionID
}

func BoundedText(s string, maxRunes int) string {
	s = strings.TrimSpace(s)
	if maxRunes <= 0 || s == "" {
		return ""
	}
	if utf8.RuneCountInString(s) <= maxRunes {
		return s
	}
	runes := []rune(s)
	if maxRunes <= 3 {
		return string(runes[:maxRunes])
	}
	return string(runes[:maxRunes-3]) + "..."
}

