func TestStatusLineIncludesElapsedSincePreviousUpdate(t *testing.T) {
	got := StatusLine(StatusLineInput{
		TaskID:      "ddx-1234",
		TurnIndex:   22,
		Message:     "go test ./cmd/bench",
		SinceLastMS: 31624,
		Limit:       DefaultLineLimit,
